const raw = $input.item.json;
const payload = (raw && raw.body && typeof raw.body === 'object') ? raw.body : raw;

const debugInfo = {
  has_event: !!payload.event,
  event_value: payload.event || 'NINGUNO',
  has_data: !!payload.data,
  data_type: typeof payload.data,
  payload_keys: Object.keys(payload || {}).slice(0, 10).join(',')
};

const event = payload.event || payload.type || '';

// Accept messages.upsert AND messages.update that contain actual message content
// (some Evolution API versions send new messages as messages.update)
const isStatusOnly = event === 'messages.update' &&
  payload.data && !Array.isArray(payload.data) &&
  payload.data.update && !payload.data.message && !payload.data.key;

if (isStatusOnly) {
  return [{ json: { skip: true, skip_reason: 'status_update:' + event, ...debugInfo } }];
}

if (event && event !== 'messages.upsert' && event !== 'messages.update') {
  return [{ json: { skip: true, skip_reason: 'wrong_event:' + event, ...debugInfo } }];
}

let dataSource = payload.data || payload;

if (typeof dataSource === 'string') {
  try {
    dataSource = JSON.parse(Buffer.from(dataSource, 'base64').toString('utf8'));
  } catch(e1) {
    try { dataSource = JSON.parse(dataSource); }
    catch(e2) {
      return [{ json: { skip: true, skip_reason: 'data_no_parseable', ...debugInfo } }];
    }
  }
}

let msgData = null;
if (dataSource && dataSource.key) {
  msgData = dataSource;
} else if (dataSource && Array.isArray(dataSource.messages) && dataSource.messages.length > 0) {
  msgData = dataSource.messages[0];
} else if (Array.isArray(dataSource) && dataSource.length > 0) {
  msgData = dataSource[0];
} else if (dataSource && typeof dataSource === 'object') {
  msgData = dataSource;
}

if (!msgData) {
  return [{ json: { skip: true, skip_reason: 'no_msg_data', ...debugInfo } }];
}

const key = msgData.key || {};
const remoteJid = key.remoteJid || msgData.remoteJid || '';
const fromMe = key.fromMe === true || msgData.fromMe === true;
const isGroup = remoteJid.includes('@g.us');

if (fromMe)     return [{ json: { skip: true, skip_reason: 'from_me', remoteJid, ...debugInfo } }];
if (isGroup)    return [{ json: { skip: true, skip_reason: 'is_group', remoteJid, ...debugInfo } }];
if (!remoteJid) return [{ json: { skip: true, skip_reason: 'no_remote_jid', ...debugInfo } }];

const message = msgData.message || {};

// Botón clásico
const buttonId   = (message.buttonsResponseMessage && message.buttonsResponseMessage.selectedButtonId)   || null;
const buttonText = (message.buttonsResponseMessage && message.buttonsResponseMessage.selectedDisplayText) || null;

// Respuesta de lista (sendList)
const listRowId  = (message.listResponseMessage && message.listResponseMessage.singleSelectReply && message.listResponseMessage.singleSelectReply.selectedRowId) || null;
const listTitle  = (message.listResponseMessage && message.listResponseMessage.title) || null;

// ID unificado: botón o lista
const selectedId = buttonId || listRowId || null;

const texto = message.conversation
  || (message.extendedTextMessage && message.extendedTextMessage.text)
  || buttonText
  || listTitle
  || (message.imageMessage && message.imageMessage.caption)
  || (message.videoMessage && message.videoMessage.caption)
  || (message.audioMessage ? '[audio]' : null)
  || (message.documentMessage ? '[documento]' : null)
  || (message.stickerMessage ? '[sticker]' : null)
  || '[media]';

const pushName = msgData.pushName || '';
const numero = remoteJid.replace('@s.whatsapp.net', '').replace(/^[+]/, '');

if (!numero) return [{ json: { skip: true, skip_reason: 'no_numero', ...debugInfo } }];

const esSI = /^\s*s[i\xED]+!?\s*$/i.test(texto.trim()) || selectedId === 'btn_si';
const esNO = /^\s*no\s*$/i.test(texto.trim()) || selectedId === 'btn_no';
const esAgendar = /^\s*agendar\s*$/i.test(texto.trim());
const esSlot = /^SLOT_\d{4}-\d{2}-\d{2}_\d{2}:\d{2}$/.test(texto.trim());
const esNoReunion = /^\s*no_reunion\s*$/i.test(texto.trim());
const slotKey = esSlot ? texto.trim() : null;

return [{ json: {
  skip: false,
  numero,
  texto,
  es_si: esSI,
  es_no: esNO,
  es_agendar: esAgendar,
  es_slot: esSlot,
  es_no_reunion: esNoReunion,
  slot_key: slotKey,
  button_id: selectedId,
  nombre_remitente: pushName,
  fecha_respuesta: new Date().toISOString(),
  _debug_event: event || 'sin_evento',
  ...debugInfo
} }];

const items = $input.all();
const ex = $('Extraer y Filtrar Mensaje').first().json;

if (items.length === 0 || !items[0].json.id) {
  return [{ json: { found: false, numero: ex.numero, nombre_remitente: ex.nombre_remitente, texto: ex.texto, es_si: ex.es_si, es_no: ex.es_no, es_agendar: ex.es_agendar || false, es_slot: ex.es_slot || false, es_no_reunion: ex.es_no_reunion || false, slot_key: ex.slot_key || null, button_id: ex.button_id || null, fecha_respuesta: ex.fecha_respuesta } }];
}

const c = items[0].json;
return [{ json: {
  found: true,
  contact_id: c.id,
  name: c.name,
  phone: c.phone,
  status: c.status,
  user_id: c.user_id,
  owner_name: c.owner_name || '',
  assigned_to: c.assigned_to || null,
  company: c.company || null,
  rubro: c.rubro || '',
  numero: ex.numero,
  texto: ex.texto,
  es_si: ex.es_si,
  es_no: ex.es_no,
  es_agendar: ex.es_agendar || false,
  es_slot: ex.es_slot || false,
  es_no_reunion: ex.es_no_reunion || false,
  slot_key: ex.slot_key || null,
  slot_numero: ex.slot_numero || null,
  button_id: ex.button_id || null,
  nombre_remitente: ex.nombre_remitente,
  fecha_respuesta: ex.fecha_respuesta
} }];

const contact = $('Verificar Contacto').first().json;
const ex = $('Extraer y Filtrar Mensaje').first().json;

const ownerName = 'Carlos Perilli';
const ownerUserId = contact.user_id;

var n = String.fromCharCode(10);
const propText = '¡Genial ' + contact.name + '! 👋' + n
  + 'Te adjunto nuestra propuesta para que la puedas ver con calma 👆' + n + n
  + 'En resumen, lo que hacemos es ayudarte a que cada peso que invertís en publicidad rinda más, '
  + 'evitando los impuestos que hoy probablemente estás pagando sin darte cuenta. '
  + '¿Te gustaría agendar una charla de 15-30 minutos para verla juntos? Sin compromiso.' + n + n
  + '✅ Respondé *AGENDAR* para elegir un horario' + n + n
  + '❌ Respondé *NO* si preferís no agendar';

const inboxBody = 'Lead respondi\xF3 S\xCD \u2014 propuesta enviada autom\xE1ticamente\n\n'
  + 'Nombre: ' + contact.name + '\n'
  + 'Tel\xE9fono: ' + ex.numero + '\n'
  + 'Rubro: ' + (contact.rubro || '-') + '\n\n'
  + 'Mensaje: "' + ex.texto + '"';

return [{ json: {
  contact_id: contact.contact_id,
  contact_name: contact.name,
  contact_rubro: contact.rubro || '',
  user_id: ownerUserId,
  owner_name: ownerName,
  numero: ex.numero,
  fecha_respuesta: ex.fecha_respuesta,
  prop_text: propText,
  pdf_url: 'https://drive.google.com/uc?export=download&id=1OKqpjbrUV0sx9tg0r2UJOrZnQCmAxWnY',
  inbox_body: inboxBody,
  inbox_subject: 'S\xCD de ' + contact.name + (contact.rubro ? ' \xB7 ' + contact.rubro : ''),
  inbox_preview: 'Respondi\xF3 S\xCD \u2014 propuesta enviada autom\xE1ticamente'
} }];

const items = $input.all();
const contact = $('Verificar Contacto').first().json;
const ex = $('Extraer y Filtrar Mensaje').first().json;

const SUPABASE_URL = 'https://resxhwxubboicfpoftjp.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InJlc3hod3h1YmJvaWNmcG9mdGpwIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NzcwMDE0MSwiZXhwIjoyMDkzMjc2MTQxfQ.TqcIuu0AJLfZ61s7BYvYCrmophh1t6kLtZQDtdR-L7M';

const vendors = items.map(i => i.json).filter(v => v.id && v.permission !== 'admin');

if (vendors.length === 0) {
  return [{ json: { assigned: false, contact_id: contact.contact_id, user_id: contact.user_id } }];
}

let vendor = null;

// If contact has a company, check if another lead from same company is already assigned
if (contact.company && contact.company.trim() !== '') {
  try {
    const params = new URLSearchParams({
      select: 'assigned_to',
      user_id: 'eq.' + contact.user_id,
      company: 'ilike.' + contact.company.trim(),
      assigned_to: 'not.is.null',
      id: 'neq.' + contact.contact_id,
      limit: '1'
    });
    const resp = await fetch(SUPABASE_URL + '/rest/v1/contacts?' + params, {
      headers: { apikey: SUPABASE_KEY, Authorization: 'Bearer ' + SUPABASE_KEY }
    });
    const rows = await resp.json();
    if (Array.isArray(rows) && rows.length > 0 && rows[0].assigned_to) {
      const existingVendorId = rows[0].assigned_to;
      const match = vendors.find(v => v.member_user_id === existingVendorId);
      if (match) vendor = match;
    }
  } catch(e) { /* fall through to round-robin */ }
}

// Fallback: round-robin by least deals
if (!vendor) {
  const minDeals = Math.min(...vendors.map(v => Number(v.deals_count) || 0));
  const candidates = vendors.filter(v => (Number(v.deals_count) || 0) === minDeals);
  vendor = candidates[Math.floor(Math.random() * candidates.length)];
}

const vendorPhone = String(vendor.phone || '').replace(/D/g, '');

const waVendorText = 'Hola ' + vendor.name + '! Te asignaron un nuevo lead que respondio.

'
  + '*Nombre:* ' + contact.name + '
'
  + '*Telefono:* ' + ex.numero + '
'
  + '*Rubro:* ' + (contact.rubro || '-') + '
'
  + '*Mensaje:* "' + ex.texto + '"

'
  + 'Revisa el CRM para gestionar el lead.';

const waOwnerText = 'LEAD RESPONDIO

'
  + '*Nombre:* ' + contact.name + '
'
  + '*Numero:* ' + ex.numero + '
'
  + '*Rubro:* ' + (contact.rubro || 'Sin clasificar') + '
'
  + '*Mensaje:* "' + ex.texto + '"

'
  + '*Vendedor asignado:* ' + vendor.name;

const inboxBody = 'Respuesta WhatsApp recibida

'
  + 'Nombre: ' + contact.name + '
'
  + 'Telefono: ' + ex.numero + '
'
  + 'Rubro: ' + (contact.rubro || '-') + '

'
  + 'Mensaje del lead:
"' + ex.texto + '"

'
  + 'Vendedor asignado: ' + vendor.name;

return [{ json: {
  assigned: true,
  contact_id: contact.contact_id,
  contact_name: contact.name,
  contact_rubro: contact.rubro || '',
  user_id: contact.user_id,
  vendor_id: vendor.id,
  vendor_name: vendor.name,
  vendor_phone: vendorPhone,
  vendor_member_user_id: vendor.member_user_id || null,
  vendor_deals_ant: Number(vendor.deals_count) || 0,
  fecha_respuesta: ex.fecha_respuesta,
  wa_vendor_text: waVendorText,
  wa_owner_text: waOwnerText,
  inbox_body: inboxBody,
  inbox_preview: ex.texto.substring(0, 120),
  inbox_subject: 'WhatsApp de ' + contact.name + (contact.rubro ? ' · ' + contact.rubro : '')
} }];

const items = $input.all();
const rr = $('Asignar Round-Robin').first().json;
const dealExistia = items.length > 0 && items[0].json && items[0].json.id;
return [{ json: {
  deal_existia: dealExistia,
  contact_id: rr.contact_id,
  contact_name: rr.contact_name,
  contact_rubro: rr.contact_rubro,
  user_id: rr.user_id,
  vendor_name: rr.vendor_name,
  vendor_member_user_id: rr.vendor_member_user_id,
  vendor_phone: rr.vendor_phone,
  fecha_respuesta: rr.fecha_respuesta,
  inbox_body: rr.inbox_body,
  inbox_preview: rr.inbox_preview,
  inbox_subject: rr.inbox_subject,
  wa_vendor_text: rr.wa_vendor_text,
  wa_owner_text: rr.wa_owner_text
} }];

const items = $input.all();
const prep = $('Preparar Msg Existente').first().json;
const dealExistia = items.length > 0 && items[0].json && items[0].json.id;
return [{ json: {
  deal_existia: dealExistia,
  contact_id: prep.contact_id,
  contact_name: prep.contact_name,
  user_id: prep.user_id,
  owner_name: prep.owner_name,
  assigned_to: prep.assigned_to
} }];

const slotsResp = $input.first().json;
const contact = $('Verificar Contacto').first().json;
const crmNumber = '5491144123687';
const numEmojis = ['1⃣','2⃣','3⃣','4⃣','5⃣','6⃣'];

// Detect n8n HTTP errors (object) AND API-level errors (string)
const rawError = slotsResp && slotsResp.error !== undefined ? slotsResp.error : null;
const apiError = rawError !== null
  ? (typeof rawError === 'object' ? (rawError.message || JSON.stringify(rawError)) : String(rawError))
  : null;

const slots = slotsResp && Array.isArray(slotsResp.slots) ? slotsResp.slots : [];

if (apiError) {
  return [{ json: { numero: contact.numero, mensaje: 'En un momento te contactamos para coordinar la llamada 📞', _debug: 'API_ERROR: ' + apiError } }];
}
if (slots.length === 0) {
  return [{ json: { numero: contact.numero, mensaje: 'Por el momento no tenemos horarios disponibles. Te avisamos cuando se libere la agenda.', _debug: 'NO_SLOTS' } }];
}

var n = String.fromCharCode(10);
var msg = '📅 Estos son los horarios disponibles:' + n + n;
slots.slice(0, 6).forEach(function(slot, i) {
  msg += numEmojis[i] + ' ' + slot.label + n;
  msg += 'https://wa.me/' + crmNumber + '?text=' + encodeURIComponent(slot.key) + n + n;
});
msg += 'Tocá el horario que más te convenga 👆';

return [{ json: { numero: contact.numero, mensaje: msg } }];

const booking = $input.first().json;
const contact = $('Verificar Contacto').first().json;

const label = booking.slot_label || 'el horario seleccionado';
const meetLink = booking.meet_link || null;

const confirmMsg = '\u2705 *\u00A1Reuni\xF3n confirmada!*\n\n'
  + '\uD83D\uDCC5 ' + label + '\n'
  + '\u23F1 Duraci\xF3n: 30 minutos\n'
  + (meetLink ? '\uD83D\uDCBB Google Meet: ' + meetLink + '\n' : '')
  + '\n\u00A1Te esperamos! Si necesit\xE1s cambiar el horario respond\xE9 *AGENDAR* y te mandamos nuevas opciones.';

const ownerMsg = 'REUNI\xD3N AGENDADA \uD83D\uDCC5\n\n'
  + '*Contacto:* ' + contact.name + '\n'
  + '*Tel\xE9fono:* ' + contact.numero + '\n'
  + '*Horario:* ' + label + '\n'
  + (meetLink ? '*Meet:* ' + meetLink : '');

return [{ json: {
  numero: contact.numero,
  confirm_msg: confirmMsg,
  owner_msg: ownerMsg,
  slot_label: label,
  contact_id: contact.contact_id,
  user_id: contact.user_id,
  contact_name: contact.name
} }];
